import { useState } from 'react';
import { ArrowRight, ArrowUpRight, ArrowDownLeft, Plus, Wallet, Shield, Zap, RefreshCw } from 'lucide-react';
import { useWallet } from '../context/WalletContext';
import StreamList from '../components/StreamList';
import { supportedPaymentAssets } from '../contactInfo.js';
import Select from '../components/ui/Select';

const DURATION_OPTIONS = [
  { label: '1 Hour',   seconds: 3600 },
  { label: '24 Hours', seconds: 86400 },
  { label: '7 Days',   seconds: 604800 },
  { label: '30 Days',  seconds: 2592000 },
];

export default function Streams() {
  const {
    walletAddress,
    paymentBalance,
    paymentTokenSymbol,
    incomingStreams,
    outgoingStreams,
    isLoadingStreams,
    isProcessing,
    createStream,
    withdraw,
    cancel,
    formatEth,
    fetchPaymentBalance,
    refreshStreams,
    xlmBalance,
  } = useWallet();

  const [recipient, setRecipient]   = useState('');
  const [amount, setAmount]         = useState('');
  const [duration, setDuration]     = useState(DURATION_OPTIONS[0].seconds);
  const [sessionId, setSessionId]   = useState('');
  const [selectedAssetSymbol, setSelectedAssetSymbol] = useState(
    supportedPaymentAssets[0]?.symbol || 'USDC',
  );

  const selectedAsset = supportedPaymentAssets.find((asset) => asset.symbol === selectedAssetSymbol)
    || supportedPaymentAssets[0];

  const handleCreate = async (e) => {
    e.preventDefault();
    if (!recipient || !amount) return;
    await createStream(recipient, duration, amount, "{}", { asset: selectedAsset });
    setRecipient('');
    setAmount('');
  };

  const handleWithdraw = async (e) => {
    e.preventDefault();
    if (!sessionId) return;
    await withdraw(Number(sessionId));
    setSessionId('');
  };

  return (
    <div className="p-4 sm:p-8 max-w-[1600px] mx-auto space-y-12">
      {/* Stats Bar */}
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
       <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm relative overflow-hidden">
          <div className="absolute top-4 right-4">
            <span className="flex h-2 w-2">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-secondary opacity-75"></span>
              <span className="relative inline-flex rounded-full h-2 w-2 bg-secondary"></span>
            </span>
          </div>
          <div className="flex items-center gap-3 mb-4">
            <div className="w-8 h-8 rounded-lg bg-slate-900 flex items-center justify-center text-white">
              <Shield size={16} />
            </div>
            <p className="text-[10px] font-label font-bold uppercase tracking-widest text-slate-400">Earning</p>
          </div>
          <h4 className="text-xl font-headline font-bold text-slate-900">{incomingStreams.length} Earning</h4>
          <p className="text-xs text-slate-400 mt-1">
            {walletAddress ? `${walletAddress.slice(0, 6)}...${walletAddress.slice(-4)}` : 'Not connected'}
          </p>
        </div>

        <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm flex justify-between items-center relative overflow-hidden">
          <div className="absolute -top-12 -right-12 w-48 h-48 bg-teal-50 blur-[80px] rounded-full"></div>
          <div className="relative z-10">
            <p className="text-[10px] font-label font-bold uppercase tracking-[0.2em] text-slate-400 mb-2">Spending</p>
            <div className="flex items-baseline gap-2">
              <h3 className="text-4xl font-headline font-black text-slate-900 tracking-tighter">{outgoingStreams.length}</h3>
              <span className="text-lg font-headline font-bold text-secondary">streams</span>
            </div>
          </div>
          <div className="relative z-10 w-14 h-14 rounded-2xl bg-teal-50 flex items-center justify-center text-secondary">
            <ArrowUpRight size={28} />
          </div>
        </div>

        <div className="bg-white p-8 rounded-3xl border border-slate-100 shadow-sm">
          <div className="flex items-center gap-3 mb-4">
            <div className="w-8 h-8 rounded-lg bg-blue-600 flex items-center justify-center text-white">
              <Zap size={16} />
            </div>
            <p className="text-[10px] font-label font-bold uppercase tracking-widest text-slate-400">Runtime</p>
          </div>
          <h4 className="text-xl font-headline font-bold text-slate-900">Stellar Testnet</h4>
          <p className="text-xs text-slate-400 mt-1">Soroban Node v2.0.4</p>
        </div>


      </div>

      {/* Deploy Payment Job + Claim Earnings */}
      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-8 bg-white p-6 sm:p-10 rounded-[2.5rem] border border-slate-100 shadow-sm">
          <div className="flex justify-between items-center mb-10">
            <h3 className="text-3xl font-headline font-black uppercase tracking-tighter">Deploy Payment Job</h3>
            <div className="flex items-center gap-2 px-4 py-2 bg-teal-50 rounded-full">
              <span className={`w-2 h-2 rounded-full ${walletAddress ? 'bg-secondary animate-pulse' : 'bg-slate-300'}`}></span>
              <span className="text-[10px] font-label font-bold uppercase tracking-widest text-secondary">
                {walletAddress ? 'Agent Ready' : 'Not Connected'}
              </span>
            </div>
          </div>
          <form onSubmit={handleCreate} className="space-y-8">
            <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
              {/* 1. Service Wallet */}
              <div className="md:col-span-1 space-y-3">
                <label className="text-[10px] font-label font-bold uppercase tracking-widest text-slate-400 ml-1">1. Service Wallet</label>
                <input
                  type="text"
                  className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-blue-200 text-sm"
                  placeholder="G... Stellar address"
                  value={recipient}
                  onChange={e => setRecipient(e.target.value)}
                  required
                />
              </div>

              {/* 2. Asset */}
              <div className="space-y-3">
                <label className="text-[10px] font-label font-bold uppercase tracking-widest text-slate-400 ml-1">2. Asset</label>
                <Select
                  options={supportedPaymentAssets.map((a) => ({ value: a.symbol, label: a.symbol, sub: a.name }))}
                  value={selectedAssetSymbol}
                  onChange={(v) => setSelectedAssetSymbol(String(v))}
                />
              </div>

              {/* 3. Budget */}
              <div className="space-y-3">
                <label className="text-[10px] font-label font-bold uppercase tracking-widest text-slate-400 ml-1">3. Budget</label>
                <div className="relative">
                  <input
                    type="number"
                    min="0.01"
                    step="0.01"
                    className="w-full bg-slate-50 border border-slate-100 rounded-2xl px-5 py-4 focus:outline-none focus:ring-2 focus:ring-blue-200 text-sm pr-16"
                    placeholder="0.00"
                    value={amount}
                    onChange={e => setAmount(e.target.value)}
                    required
                  />
                  <span className="absolute right-5 top-1/2 -translate-y-1/2 text-slate-400 text-xs font-bold">
                    {selectedAsset?.symbol || 'USDC'}
                  </span>
                </div>
                <p className="text-[11px] text-slate-400 ml-1">
                  Bal: {selectedAsset?.symbol === 'XLM'
                    ? `${parseFloat(xlmBalance || '0').toFixed(2)} XLM`
                    : `${parseFloat(paymentBalance || '0').toFixed(2)} ${selectedAsset?.symbol || 'USDC'}`}
                </p>
              </div>

              {/* 4. Duration */}
              <div className="space-y-3">
                <label className="text-[10px] font-label font-bold uppercase tracking-widest text-slate-400 ml-1">4. Duration</label>
                <Select
                  options={DURATION_OPTIONS.map((o) => ({ value: o.seconds, label: o.label }))}
                  value={duration}
                  onChange={(v) => setDuration(Number(v))}
                />
              </div>
            </div>
            <button
              type="submit"
              disabled={isProcessing || !walletAddress}
              className="w-full md:w-auto px-12 py-5 bg-primary text-white rounded-2xl font-headline font-black text-lg uppercase tracking-tighter hover:shadow-2xl hover:shadow-blue-500/30 hover:-translate-y-1 transition-all flex items-center justify-center gap-3 disabled:opacity-50 disabled:cursor-not-allowed disabled:hover:translate-y-0"
            >
              {isProcessing ? 'Deploying...' : <><Plus size={20} /> Deploy Agent Payment <ArrowRight size={20} /></>}
            </button>
          </form>
        </div>

        <div className="lg:col-span-4 bg-slate-50 p-6 sm:p-10 rounded-[2.5rem] border border-slate-100 flex flex-col justify-between">
          <div>
            <div className="w-12 h-12 rounded-2xl bg-white flex items-center justify-center text-primary shadow-sm mb-8">
              <Wallet size={24} />
            </div>
            <h3 className="text-2xl font-headline font-black uppercase tracking-tighter mb-4">Claim Earnings</h3>
            <p className="text-slate-500 text-sm leading-relaxed mb-8">Enter a session ID to claim streamed funds earned by your agent.</p>
            <input
              type="text"
              className="w-full bg-white border-none rounded-2xl px-6 py-4 focus:ring-2 focus:ring-blue-200 text-sm mb-4"
              placeholder="Session ID (e.g. 42)"
              value={sessionId}
              onChange={e => setSessionId(e.target.value)}
            />
          </div>
          <button
            onClick={handleWithdraw}
            disabled={isProcessing || !sessionId || !walletAddress}
            className="w-full py-4 border-2 border-primary text-primary rounded-2xl font-label uppercase tracking-widest text-xs font-bold hover:bg-primary hover:text-white transition-all disabled:opacity-50 disabled:cursor-not-allowed"
          >
            Claim Session
          </button>
        </div>
      </div>

      {/* Stream Lists */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {[
          { icon: ArrowDownLeft, label: 'Earning Streams', color: 'text-secondary', streams: incomingStreams, variant: 'incoming' },
          { icon: ArrowUpRight,  label: 'Spending Streams', color: 'text-primary',   streams: outgoingStreams, variant: 'outgoing' },
        ].map(({ icon: Icon, label, color, streams: list, variant }) => (
          <div key={label} className="space-y-6">
            <div className="flex justify-between items-center px-2">
              <div className="flex items-center gap-3">
                <Icon className={color} size={20} />
                <h3 className="text-xl font-headline font-bold text-slate-900">{label}</h3>
              </div>
              <button onClick={refreshStreams} className="text-slate-400 hover:text-primary transition-colors">
                <RefreshCw size={16} />
              </button>
            </div>
            {list.length === 0 && !isLoadingStreams ? (
              <div className="bg-slate-50 rounded-[2.5rem] p-12 border border-slate-100 flex flex-col items-center justify-center text-center min-h-[300px]">
                <div className="w-16 h-16 rounded-2xl bg-white flex items-center justify-center text-slate-200 mb-6">
                  <Icon size={32} />
                </div>
                <p className="text-slate-400 text-sm">
                  {variant === 'incoming' ? 'No incoming streams detected.' : "You haven't initialized any streams."}
                </p>
              </div>
            ) : (
              <StreamList
                title=""
                streams={list}
                variant={variant}
                formatEth={formatEth}
                onWithdraw={withdraw}
                onCancel={cancel}
                isLoading={isLoadingStreams}
              />
            )}
          </div>
        ))}
      </div>

      {/* Service Directory */}
      <div className="bg-slate-50 p-6 sm:p-10 rounded-[2.5rem] border border-slate-100">
        <div className="flex justify-between items-center mb-10">
          <div>
            <h3 className="text-2xl font-headline font-black uppercase tracking-tighter mb-2">Protected Service Directory</h3>
            <p className="text-slate-500 text-sm">Configure backend routes that require active payment sessions.</p>
          </div>
          <button className="px-6 py-3 bg-slate-900 text-white rounded-xl font-label text-[10px] font-bold uppercase tracking-widest flex items-center gap-2 hover:bg-primary transition-colors">
            <Plus size={16} /> Register Route
          </button>
        </div>
        <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
          {[1,2,3,4].map(i => (
            <div key={i} className="bg-white/50 border border-slate-100 rounded-2xl p-8 flex flex-col items-center justify-center text-center">
              <div className="w-10 h-10 rounded-lg bg-slate-100 flex items-center justify-center text-slate-300 mb-4">
                <Shield size={20} />
              </div>
              <p className="text-[10px] font-label font-bold uppercase tracking-widest text-slate-300">Empty Slot</p>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

import { useState, useRef, useEffect, useCallback } from 'react';
import { Send, Bot, Activity, Zap, Store, TrendingUp, RefreshCw, Play, Pause, Settings, AlertTriangle, CheckCircle, Clock, ArrowUpRight, ArrowDownLeft, Target } from 'lucide-react';
import { motion, AnimatePresence } from 'motion/react';
import { useWallet } from '../context/WalletContext';
import { fetchRwaAssets } from '../services/rwaApi.js';
import { mapApiAssetToUiAsset } from './rwa/rwaData';
import { cn } from '../lib/cn';

// ─── Types ────────────────────────────────────────────────────────────────────

type AgentStatus = 'running' | 'paused' | 'idle';

type LogEntry = {
  id: number;
  ts: number;
  type: 'action' | 'decision' | 'info' | 'error' | 'profit';
  message: string;
  detail?: string;
  amount?: string;
  asset?: string;
};

type ChatMessage = {
  role: 'human' | 'agent';
  text: string;
  ts: number;
};

type AgentRule = {
  id: string;
  label: string;
  enabled: boolean;
  value: string;
  unit: string;
};

// ─── Mock autonomous log generator ───────────────────────────────────────────

let logId = 0;
const MOCK_ACTIONS: Omit<LogEntry, 'id' | 'ts'>[] = [
  { type: 'decision', message: 'Scanning marketplace for yield opportunities', detail: 'Evaluating 3 assets' },
  { type: 'action',   message: 'Opened rental stream on Azure Heights Residence', detail: 'Session #12 · 30 days', amount: '+8.2% APY', asset: 'Real Estate' },
  { type: 'profit',   message: 'Claimed yield from Skyline Logistics Hub', detail: 'Session #9 settled', amount: '+2.4 USDC' },
  { type: 'decision', message: 'Holding — vehicle asset yield below threshold', detail: 'Min yield: 5% · Current: 3.1%' },
  { type: 'action',   message: 'Cancelled underperforming stream', detail: 'Session #7 · Refund: 12.5 USDC', amount: '+12.5 USDC' },
  { type: 'info',     message: 'Portfolio rebalance check complete', detail: '2 active rentals · 1 pending claim' },
  { type: 'action',   message: 'Deployed payment stream to equipment provider', detail: 'Session #13 · 7 days · 5 USDC', amount: '-5.0 USDC' },
  { type: 'profit',   message: 'Flash advance executed on yield vault', detail: 'Advance: 18.3 USDC', amount: '+18.3 USDC' },
];

function makeLog(override?: Partial<LogEntry>): LogEntry {
  const base = MOCK_ACTIONS[logId % MOCK_ACTIONS.length];
  return { ...base, ...override, id: ++logId, ts: Date.now() };
}

// ─── Sub-components ───────────────────────────────────────────────────────────

function LogRow({ entry }: { entry: LogEntry }) {
  const icons = {
    action:   { Icon: Zap,          color: 'text-primary',    bg: 'bg-blue-50' },
    decision: { Icon: Target,       color: 'text-purple-600', bg: 'bg-purple-50' },
    info:     { Icon: Activity,     color: 'text-slate-500',  bg: 'bg-slate-100' },
    error:    { Icon: AlertTriangle,color: 'text-red-500',    bg: 'bg-red-50' },
    profit:   { Icon: TrendingUp,   color: 'text-secondary',  bg: 'bg-teal-50' },
  };
  const { Icon, color, bg } = icons[entry.type];
  const time = new Date(entry.ts).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' });

  return (
    <motion.div
      initial={{ opacity: 0, x: -10 }}
      animate={{ opacity: 1, x: 0 }}
      className="flex items-start gap-3 py-3 border-b border-slate-50 last:border-0"
    >
      <div className={`w-7 h-7 rounded-lg flex items-center justify-center shrink-0 mt-0.5 ${bg}`}>
        <Icon size={13} className={color} />
      </div>
      <div className="flex-1 min-w-0">
        <p className="text-sm text-slate-800 font-medium leading-snug">{entry.message}</p>
        {entry.detail && <p className="text-xs text-slate-400 mt-0.5">{entry.detail}</p>}
      </div>
      <div className="text-right shrink-0">
        {entry.amount && (
          <p className={`text-xs font-bold ${entry.amount.startsWith('+') ? 'text-secondary' : 'text-red-500'}`}>
            {entry.amount}
          </p>
        )}
        <p className="text-[10px] text-slate-300 mt-0.5">{time}</p>
      </div>
    </motion.div>
  );
}

function StatPill({ icon: Icon, label, value, color }: { icon: any; label: string; value: string; color: string }) {
  return (
    <div className="flex items-center gap-2 bg-white border border-slate-100 rounded-xl px-4 py-2.5 shadow-sm">
      <Icon size={14} className={color} />
      <div>
        <p className="text-[9px] font-label uppercase tracking-widest text-slate-400">{label}</p>
        <p className={`text-sm font-headline font-bold ${color}`}>{value}</p>
      </div>
    </div>
  );
}

// ─── Main ─────────────────────────────────────────────────────────────────────

export default function AgentConsolePage() {
  const { walletAddress, paymentBalance, xlmBalance, outgoingStreams, incomingStreams, formatEth, withdraw, cancel, refreshStreams } = useWallet();
  const shortAddress = walletAddress ? `${walletAddress.slice(0, 6)}…${walletAddress.slice(-4)}` : 'Not connected';
  const isConnected = Boolean(walletAddress);

  const [agentStatus, setAgentStatus] = useState<AgentStatus>('idle');
  const [logs, setLogs] = useState<LogEntry[]>([makeLog({ type: 'info', message: 'Agent initialized. Configure rules and press Run to start.', detail: 'Stellar Testnet · Ready' })]);
  const [totalProfit, setTotalProfit] = useState(0);
  const [actionsCount, setActionsCount] = useState(0);
  const [rules, setRules] = useState<AgentRule[]>([
    { id: 'min_yield',    label: 'Min yield target',     enabled: true,  value: '5',   unit: '%' },
    { id: 'max_budget',   label: 'Max budget per trade',  enabled: true,  value: '50',  unit: 'USDC' },
    { id: 'auto_claim',   label: 'Auto-claim threshold',  enabled: true,  value: '1',   unit: 'USDC' },
    { id: 'auto_renew',   label: 'Auto-renew sessions',   enabled: false, value: '24',  unit: 'hrs before' },
  ]);
  const [chatMessages, setChatMessages] = useState<ChatMessage[]>([{
    role: 'agent',
    text: 'Agent ready. Press Run to start autonomous trading, or ask me anything.',
    ts: Date.now(),
  }]);
  const [chatInput, setChatInput] = useState('');
  const [isThinking, setIsThinking] = useState(false);
  const [showSettings, setShowSettings] = useState(false);

  const loopRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const logBottomRef = useRef<HTMLDivElement>(null);
  const chatBottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => { logBottomRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [logs]);
  useEffect(() => { chatBottomRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [chatMessages]);

  const addLog = useCallback((entry: Omit<LogEntry, 'id' | 'ts'>) => {
    setLogs((l) => [...l.slice(-99), makeLog(entry)]);
    if (entry.type === 'profit' && entry.amount) {
      const val = parseFloat(entry.amount.replace('+', '')) || 0;
      setTotalProfit((p) => Math.round((p + val) * 100) / 100);
    }
    if (entry.type === 'action') setActionsCount((c) => c + 1);
  }, []);

  const startAgent = useCallback(() => {
    setAgentStatus('running');
    addLog({ type: 'info', message: 'Autonomous agent started', detail: `Rules active: ${rules.filter(r => r.enabled).length}` });
    loopRef.current = setInterval(() => {
      const pick = MOCK_ACTIONS[Math.floor(Math.random() * MOCK_ACTIONS.length)];
      addLog(pick);
    }, 4000);
  }, [addLog, rules]);

  const pauseAgent = useCallback(() => {
    setAgentStatus('paused');
    if (loopRef.current) clearInterval(loopRef.current);
    addLog({ type: 'info', message: 'Agent paused by operator', detail: 'Resume anytime' });
  }, [addLog]);

  const stopAgent = useCallback(() => {
    setAgentStatus('idle');
    if (loopRef.current) clearInterval(loopRef.current);
    addLog({ type: 'info', message: 'Agent stopped', detail: `Session summary: ${actionsCount} actions` });
  }, [addLog, actionsCount]);

  useEffect(() => () => { if (loopRef.current) clearInterval(loopRef.current); }, []);

  const sendChat = useCallback(async () => {
    const text = chatInput.trim();
    if (!text || isThinking) return;
    setChatInput('');
    setChatMessages((m) => [...m, { role: 'human', text, ts: Date.now() }]);
    setIsThinking(true);
    try {
      const context = { walletAddress, usdcBalance: paymentBalance, xlmBalance, outgoingStreams: outgoingStreams.length, incomingStreams: incomingStreams.length, agentStatus, actionsCount, totalProfit, network: 'Stellar Testnet' };
      const res = await fetch('http://localhost:3001/api/agent/chat', {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ message: text, context }),
      });
      const data = await res.json();
      setChatMessages((m) => [...m, { role: 'agent', text: data.reply || 'No response.', ts: Date.now() }]);
    } catch {
      setChatMessages((m) => [...m, { role: 'agent', text: 'Could not reach agent backend.', ts: Date.now() }]);
    } finally {
      setIsThinking(false);
    }
  }, [chatInput, isThinking, walletAddress, paymentBalance, xlmBalance, outgoingStreams, incomingStreams, agentStatus, actionsCount, totalProfit]);

  const statusConfig = {
    running: { label: 'Running',  color: 'text-secondary',    bg: 'bg-emerald-50',  dot: 'bg-secondary animate-pulse' },
    paused:  { label: 'Paused',   color: 'text-amber-600',    bg: 'bg-amber-50',    dot: 'bg-amber-400' },
    idle:    { label: 'Idle',     color: 'text-slate-500',    bg: 'bg-slate-100',   dot: 'bg-slate-300' },
  }[agentStatus];

  return (
    <div className="flex flex-col h-[calc(100vh-65px)] bg-slate-50/50">

      {/* ── Top control bar ── */}
      <div className="flex items-center justify-between px-6 py-3 bg-white border-b border-slate-100 shrink-0 gap-4 flex-wrap">
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 rounded-xl ethereal-gradient flex items-center justify-center shadow-md shadow-blue-500/20">
            <Bot size={16} className="text-white" />
          </div>
          <div>
            <p className="text-sm font-bold font-headline text-slate-900">Autonomous Agent</p>
            <p className="text-[10px] font-mono text-slate-400">{shortAddress}</p>
          </div>
          <div className={`flex items-center gap-1.5 px-3 py-1 rounded-full text-[10px] font-bold ${statusConfig.bg} ${statusConfig.color}`}>
            <span className={`w-1.5 h-1.5 rounded-full ${statusConfig.dot}`} />
            {statusConfig.label}
          </div>
        </div>

        <div className="flex items-center gap-2">
          <StatPill icon={TrendingUp}    label="Total Profit"  value={`+${totalProfit.toFixed(2)} USDC`} color="text-secondary" />
          <StatPill icon={Zap}           label="Actions"       value={String(actionsCount)}               color="text-primary" />
          <StatPill icon={ArrowUpRight}  label="Spending"      value={String(outgoingStreams.length)}      color="text-primary" />
          <StatPill icon={ArrowDownLeft} label="Earning"       value={String(incomingStreams.length)}      color="text-secondary" />
        </div>

        <div className="flex items-center gap-2">
          <button onClick={() => setShowSettings(s => !s)}
            className={cn('p-2.5 rounded-xl border transition-all', showSettings ? 'bg-blue-50 border-blue-200 text-primary' : 'border-slate-100 text-slate-400 hover:text-primary hover:bg-slate-50')}>
            <Settings size={16} />
          </button>
