import { useState } from 'react';
import { NavLink } from 'react-router-dom';
import { LayoutDashboard, Zap, Store, Bot, FileText, X, ChevronRight, Layers } from 'lucide-react';
import { cn } from '../lib/cn';
import { useWallet } from '../context/WalletContext';

const navItems = [
  { icon: LayoutDashboard, label: 'Agent Hub',       href: '/app',              sub: 'Overview & balances' },
  { icon: Zap,             label: 'Payment Streams', href: '/app/streams',      sub: 'Stream USDC · XLM' },
  { icon: Store,           label: 'Marketplace',     href: '/app/marketplace',  sub: 'Browse · Rent · Trade' },
  { icon: Layers,          label: 'RWA Studio',      href: '/app/rwa',          sub: 'Mint · Manage · Attest' },
  { icon: Bot,             label: 'My Agent',        href: '/app/agent',        sub: 'Config · Decisions' },
];

function SidebarContent({ onNavClick }: { onNavClick?: () => void }) {
  const { walletAddress } = useWallet();
  const shortAddress = walletAddress
    ? `${walletAddress.slice(0, 6)}…${walletAddress.slice(-4)}`
    : null;

  return (
    <div className="flex flex-col h-full py-6">
      {/* Logo */}
      <div className="px-6 mb-10">
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 rounded-xl ethereal-gradient flex items-center justify-center shadow-lg shadow-blue-500/20">
            <Bot size={18} className="text-white" />
          </div>
          <div>
            <h1 className="text-sm font-black text-slate-900 font-headline leading-tight tracking-tight">Stream Engine</h1>
            <div className="flex items-center gap-1.5 mt-0.5">
              <span className="w-1.5 h-1.5 rounded-full bg-secondary animate-pulse" />
              <span className="text-[9px] font-label uppercase tracking-widest text-slate-400">Agent Network</span>
            </div>
          </div>
        </div>
      </div>

      {/* Nav */}
      <nav className="flex-1 px-3 space-y-1">
        {navItems.map((item) => (
          <NavLink
            key={item.href}
            to={item.href}
            end={item.href === '/app'}
            onClick={onNavClick}
            className={({ isActive }) => cn(
              'flex items-center gap-3 px-4 py-3 rounded-2xl transition-all duration-200 group',
              isActive
                ? 'bg-blue-50 text-blue-700'
                : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'
            )}
          >
            {({ isActive }) => (
              <>
                <div className={cn(
                  'w-8 h-8 rounded-xl flex items-center justify-center shrink-0 transition-colors',
                  isActive ? 'bg-blue-100 text-blue-600' : 'bg-slate-100 text-slate-400 group-hover:bg-slate-200'
                )}>
                  <item.icon size={16} />
                </div>
                <div className="flex-1 min-w-0">
                  <p className={cn('text-sm font-bold font-headline leading-tight', isActive ? 'text-blue-700' : 'text-slate-700')}>{item.label}</p>
                  <p className="text-[10px] text-slate-400 truncate">{item.sub}</p>
                </div>
                {isActive && <ChevronRight size={14} className="text-blue-400 shrink-0" />}
              </>
            )}
          </NavLink>
        ))}
      </nav>

      {/* Bottom */}
      <div className="px-3 mt-4 space-y-2">
        {walletAddress && (
          <div className="mx-1 bg-gradient-to-br from-slate-50 to-blue-50 rounded-2xl p-4 border border-blue-100">
            <p className="text-[9px] font-label uppercase tracking-widest text-slate-400 mb-1">Agent Wallet</p>
            <p className="text-xs font-mono font-bold text-slate-700">{shortAddress}</p>
            <div className="flex items-center gap-1 mt-1.5">
              <span className="w-1.5 h-1.5 rounded-full bg-secondary" />
              <span className="text-[9px] text-secondary font-bold">Connected · Stellar Testnet</span>
            </div>
          </div>
        )}
        <NavLink
          to="/app/docs"
          onClick={onNavClick}
          className={({ isActive }) => cn(
            'flex items-center gap-3 px-4 py-2.5 rounded-xl transition-all text-xs font-headline',
            isActive ? 'text-blue-600 font-bold bg-blue-50' : 'text-slate-400 hover:text-slate-600'
          )}
        >
          <FileText size={14} /><span>Docs</span>
        </NavLink>
      </div>
    </div>
  );
}

export default function Sidebar({ isOpen, onClose }: { isOpen: boolean; onClose: () => void }) {
  return (
    <>
      <aside className="hidden lg:flex flex-col h-screen w-64 fixed left-0 top-0 z-40 bg-white/90 backdrop-blur-lg border-r border-slate-100">
        <SidebarContent />
      </aside>

      {isOpen && (
        <div className="lg:hidden fixed inset-0 z-50 flex">
          <div className="absolute inset-0 bg-black/40 backdrop-blur-sm" onClick={onClose} />
          <aside className="relative w-72 bg-white h-full shadow-2xl flex flex-col">
            <button onClick={onClose} className="absolute top-4 right-4 p-2 rounded-xl text-slate-400 hover:bg-slate-100 transition-colors">
              <X size={20} />
            </button>
            <SidebarContent onNavClick={onClose} />
          </aside>
        </div>
      )}
    </>
  );
}

